Logica di inizializzazione dello scanner migliorata per evitare conflitti in React Strict Mode e garantire che la fotocamera si avvii correttamente.

```tsx
import React, { useEffect, useState, useRef } from 'react';
import { Html5QrcodeScanner } from 'html5-qrcode';
import { api } from '../services/api';
import { Ticket, UserRole } from '../types';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import { CheckCircle, XCircle, AlertTriangle, RefreshCw, Search, ScanLine } from 'lucide-react';

const Scanner: React.FC = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [scanResult, setScanResult] = useState<Ticket | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [manualCode, setManualCode] = useState('');
  const [loading, setLoading] = useState(false);
  const [scannerReady, setScannerReady] = useState(false);

  // Ref to hold the scanner instance
  const scannerInstanceRef = useRef<Html5QrcodeScanner | null>(null);

  useEffect(() => {
    if (!user || user.role !== UserRole.ASSOCIAZIONE) {
        navigate('/');
        return;
    }

    // If we have a result, error, or loading, we don't need the scanner
    const shouldShowScanner = !scanResult && !error && !loading;

    if (!shouldShowScanner) {
        // Cleanup if it exists
        if (scannerInstanceRef.current) {
            scannerInstanceRef.current.clear().catch(err => console.error("Failed to clear scanner", err));
            scannerInstanceRef.current = null;
            setScannerReady(false);
        }
        return;
    }

    // Initialize Scanner with a slight delay to ensure DOM is ready
    const timer = setTimeout(() => {
        // Prevent double init
        if (scannerInstanceRef.current) return;

        const element = document.getElementById('reader');
        if (!element) return;

        try {
            const scanner = new Html5QrcodeScanner(
                "reader",
                { 
                    fps: 10, 
                    qrbox: { width: 250, height: 250 },
                    aspectRatio: 1.0,
                    showTorchButtonIfSupported: true,
                    rememberLastUsedCamera: true
                },
                /* verbose= */ false
            );

            scannerInstanceRef.current = scanner;

            const onScanSuccess = (decodedText: string) => {
               // Pause/Clear immediately on success to prevent multiple reads
               if(scannerInstanceRef.current) {
                   scannerInstanceRef.current.clear().then(() => {
                       scannerInstanceRef.current = null;
                       setScannerReady(false);
                       handleValidation(decodedText);
                   }).catch(err => {
                       console.error("Failed to clear", err);
                       handleValidation(decodedText);
                   });
               }
            };

            scanner.render(onScanSuccess, (err) => { 
                // Ignore frame parse errors (very common while scanning)
            });

            setScannerReady(true);
        } catch (e) {
            console.error("Scanner init error:", e);
        }
    }, 100);

    // Cleanup function
    return () => {
        clearTimeout(timer);
        if (scannerInstanceRef.current) {
            scannerInstanceRef.current.clear().catch(err => console.error("Cleanup error", err));
            scannerInstanceRef.current = null;
            setScannerReady(false);
        }
    };
  }, [user, navigate, scanResult, error, loading]);

  const handleValidation = async (qrCodeId: string) => {
      setLoading(true);
      setError(null);
      setScanResult(null);

      try {
          const ticket = await api.events.validateTicket(qrCodeId);

          // Verify ownership (Client side check as double safety, server handles it too)
          const orgId = typeof ticket.event.organization === 'string' 
            ? ticket.event.organization 
            : ticket.event.organization._id;

          if (orgId !== user?._id) {
             setError("This ticket belongs to another association's event!");
             return;
          }

          setScanResult(ticket);
      } catch (err: any) {
          if (err.message === "INVALID_TICKET") {
              setError("Invalid Ticket. Code not found.");
          } else if (err.message === "ALREADY_USED") {
              setError("Ticket ALREADY USED! Entry denied.");
          } else if (err.message === "WRONG_EVENT_ORGANIZER") {
              setError("This ticket belongs to another association.");
          } else {
              setError("Error validating ticket. Please try again.");
          }
      } finally {
          setLoading(false);
      }
  };

  const handleManualSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      if(manualCode.trim()) {
          handleValidation(manualCode.trim());
      }
  };

  const resetScanner = () => {
      setScanResult(null);
      setError(null);
      setManualCode('');
      setLoading(false);
      // This state change will trigger useEffect to re-mount the scanner
  };

  return (
    <div className="min-h-screen bg-gray-900 text-white flex flex-col">
      <div className="p-4 bg-indigo-900 shadow-lg flex justify-between items-center z-10">
          <h1 className="text-xl font-bold flex items-center">
              <ScanLine className="mr-2" /> Ticket Scanner
          </h1>
          <button onClick={() => navigate('/dashboard')} className="text-sm text-indigo-200 hover:text-white">
              Exit
          </button>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center p-4">

          {/* SCANNER VIEWPORT */}
          {(!scanResult && !error && !loading) && (
              <div className="w-full max-w-md bg-black rounded-xl overflow-hidden shadow-2xl border-2 border-indigo-500 relative">
                   {/* Explicit height to force visibility before video loads */}
                   <div id="reader" className="w-full min-h-[300px] bg-black"></div>

                   {!scannerReady && (
                       <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                           <p className="text-indigo-300 animate-pulse">Initializing Camera...</p>
                       </div>
                   )}
              </div>
          )}

          {/* LOADING */}
          {loading && (
              <div className="flex flex-col items-center animate-in fade-in duration-200">
                  <div className="w-16 h-16 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-4"></div>
                  <p className="text-xl font-bold">Verifying...</p>
              </div>
          )}

          {/* RESULT: SUCCESS */}
          {scanResult && (
              <div className="bg-white text-gray-900 rounded-2xl p-8 max-w-md w-full text-center shadow-2xl animate-in zoom-in duration-300">
                  <div className="w-24 h-24 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
                      <CheckCircle className="w-12 h-12 text-green-600" />
                  </div>
                  <h2 className="text-3xl font-bold text-green-600 mb-2">Access Granted</h2>
                  <div className="bg-gray-100 rounded-lg p-4 mb-6 text-left border border-gray-200">
                      <p className="text-lg font-bold text-indigo-900 mb-3 leading-tight">{scanResult.event.title}</p>
                      <div className="space-y-1">
                          <p className="text-sm text-gray-500 uppercase tracking-wide font-semibold">Guest</p>
                          <p className="text-xl font-bold text-gray-900">{scanResult.ticketHolderName}</p>
                      </div>
                      <div className="mt-3 space-y-1">
                          <p className="text-sm text-gray-500 uppercase tracking-wide font-semibold">PR List</p>
                          <p className="text-lg font-bold text-indigo-600">{scanResult.prList || "None"}</p>
                      </div>
                  </div>
                  <button onClick={resetScanner} className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 rounded-xl flex items-center justify-center transition-colors">
                      <RefreshCw className="w-5 h-5 mr-2" /> Scan Next
                  </button>
              </div>
          )}

          {/* RESULT: ERROR */}
          {error && (
              <div className="bg-white text-gray-900 rounded-2xl p-8 max-w-md w-full text-center shadow-2xl animate-in shake duration-300">
                  <div className="w-24 h-24 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4">
                      {error.includes("ALREADY") ? (
                           <AlertTriangle className="w-12 h-12 text-red-600" />
                      ) : (
                           <XCircle className="w-12 h-12 text-red-600" />
                      )}
                  </div>
                  <h2 className="text-3xl font-bold text-red-600 mb-4">Access Denied</h2>
                  <p className="text-xl font-medium text-gray-800 mb-8 leading-snug">{error}</p>
                  <button onClick={resetScanner} className="w-full bg-gray-800 hover:bg-gray-900 text-white font-bold py-3 rounded-xl flex items-center justify-center transition-colors">
                      <RefreshCw className="w-5 h-5 mr-2" /> Try Again
                  </button>
              </div>
          )}

